synthesizer_agent = Agent(
    name="rag_synthesizer",
    model="gemini-1.5-pro",
    instruction="""Synthesize answer using ONLY provided documents. Structure response:
    {
      'answer': 'Direct response grounded in sources',
      'citations': [{'doc_id': str, 'chunk_id': str, 'quote': str, 'start_pos': int}],
      'confidence': 'high|medium|low'
    }
    Never fabricate information. Flag gaps explicitly."""
)

def format_citations(response, documents):
    citations = []
    for cite in response.get('citations', []):
        doc = next(d for d in documents if d['id'] == cite['doc_id'])
        citations.append({
            'document_id': cite['doc_id'],
            'snippet': doc['content'][:200],
            'relevance_score': doc['score']
        })
    return {'answer': response['answer'], 'citations': citations}

from google.adk.sessions import Session

router_agent = Agent(
    name="rag_router",
    model="gemini-1.5-flash",
    instruction="Coordinate RAG workflow:
    1. New query вҶ’ retriever_agent
    2. Retrieved docs вҶ’ synthesizer_agent
    3. Maintain conversation history
    Respond with: {'next_agent': 'retriever|synthesizer', 'context': {...}}"
)

def orchestrate_rag(session: Session, query: str):
    history = session.get_state()

    if not history.get('retrieved_docs'):
        return {'next_agent': 'retriever_agent', 'query': query}

    return {
        'next_agent': 'synthesizer_agent',
        'context': {
            'query': query,
            'documents': history['retrieved_docs'],
            'conversation_history': history.get('messages', [])
        }
    }

def manage_session_state(session: Session, max_tokens: int = 128000):
    messages = session.get_messages()
    current_tokens = sum(len(m.content) for m in messages)

    if current_tokens > max_tokens:
        # Summarize oldest exchanges
        summary_agent = Agent(name="summarizer", model="gemini-1.5-flash")
        old_context = messages[:len(messages)//2]
        summary = summary_agent.generate(
            f"Summarize this conversation (max 4k tokens): {old_context}"
        )

        # Replace old messages with summary
        session.update_messages([
            {'role': 'system', 'content': f'Prior context summary: {summary}'}
        ] + messages[len(messages)//2:])

    return session.get_state()

