from vex_sdk import VexClient

vex_client = VexClient(api_key="vex_...")

def vex_before_agent_callback(session_data: dict, agent_name: str):
    if agent_name == "rag_synthesizer":
        documents = session_data.get('context', {}).get('documents', [])
        query = session_data.get('query', '')

        # Verify source faithfulness
        results = vex_client.verify({
            'task': 'rag_source_faithfulness',
            'query': query,
            'documents': documents,
            'threshold': 0.8  # Cosine similarity
        })

        if not results['passes']:
            return {
                'block': True,
                'reason': 'Documents insufficiently relevant to query',
                'suggested_fix': 'Expand retrieval or refine query'
            }

    return {'passes': True}

def vex_hallucination_guard(output: dict, documents: list):
    claims = extract_claims(output['answer'])  # Custom claim extraction

    verification_results = []
    for claim in claims[:5]:  # Top 5 claims
        result = vex_client.verify({
            'task': 'hallucination_detection',
            'claim': claim,
            'ground_truth_docs': documents,
            'model': 'gemini-1.5-pro',
            'threshold': 0.7
        })
        verification_results.append(result)

    hallucination_score = sum(r['confidence_score'] for r in verification_results) / len(verification_results)

    if hallucination_score < 0.75:
        output['vex_flags'] = {
            'hallucination_risk': 'high',
            'flagged_claims': [r['claim'] for r in verification_results if r['risk'] == 'high']
        }

    return output

def vex_citation_validator(response: dict, session_documents: list):
    cited_doc_ids = [c['document_id'] for c in response.get('citations', [])]
    available_doc_ids = [d['id'] for d in session_documents]

    # Check for fabricated citations
    missing_citations = set(cited_doc_ids) - set(available_doc_ids)
    if missing_citations:
        return {
            'passes': False,
            'error': f'Found {len(missing_citations)} fabricated citations: {missing_citations}',
            'severity': 'critical'
        }

    # Verify citation relevance
    citation_results = vex_client.batch_verify([
        {
            'task': 'citation_relevance',
            'query': response['answer'],
            'citation': c,
            'document': next(d for d in session_documents if d['id'] == c['document_id'])
        }
        for c in response['citations']
    ])

    valid_citations = sum(1 for r in citation_results if r['passes'])
    accuracy = valid_citations / len(response['citations'])

    return {
        'passes': accuracy > 0.9,
        'citation_accuracy': accuracy,
        'metrics': citation_results
    }
